```holoscript
object Coin @hoverable @pointable {
  geometry: 'model/coin.glb'

  animation float {
    property: 'position.y'
    from: 0
    to: 0.2
    duration: 1000
    loop: infinite
  }

  animation spin {
    property: 'rotation.y'
    from: 0
    to: 360
    duration: 2000
    loop: infinite
  }

  collectible: { value: 10, type: 'coin' }

  onPoint: {
    player.collect(this.collectible)
    particles.spawn('collect', this.position)
    audio.play('pickup')
    this.destroy()
  }
}
```

```holoscript
object Door @pointable {
  geometry: 'model/door.glb'
  state: 'closed'
  isLocked: false

  states: {
    closed: { rotation: [0, 0, 0] }
    open: { rotation: [0, -90, 0] }
  }

  transition: {
    duration: 800
    easing: 'easeOutBack'
  }

  onPoint: {
    if (this.isLocked) {
      audio.play('locked')
      ui.showMessage('Door is locked')
    } else {
      this.state = this.state == 'closed' ? 'open' : 'closed'
      audio.play(this.state == 'open' ? 'door_open' : 'door_close')
    }
  }
}
```

```holoscript
object TriggerZone {
  geometry: 'box'
  size: [3, 2, 3]
  visible: false

  trigger: {
    layers: ['Player']
    once: true
  }

  onTriggerEnter(other): {
    if (other.tag == 'Player') {
      game.startCutscene('intro')
    }
  }
}
```

Set `visible: false` for invisible triggers. Use `once: true` to fire only once.

```holoscript
object Teleporter @pointable {
  geometry: 'cylinder'
  size: [1, 0.1, 1]
  color: '#00ffff'

  particles: {
    type: 'teleport_sparkle'
    emitFrom: 'surface'
  }

  destination: 'next_level'

  onPoint: {
    effects.teleportOut(player)
    setTimeout(() => {
      player.teleportTo(this.destination)
      effects.teleportIn(player)
    }, 1000)
  }
}
```

```holoscript
object Hammer @grabbable {
  geometry: 'model/hammer.glb'

  weapon: {
    type: 'melee'
    damage: 23
    attackSpeed: 1.0
  }

  physics: { mass: 2 }

  onSwing(velocity): {
    if (velocity.magnitude > 2) {
      let hits = physics.overlapSphere(this.tipPosition, 0.3)
      hits.forEach(hit => {
        if (hit.health) {
          hit.takeDamage(this.weapon.damage)
        }
      })
    }
  }
}
```

Use `onSwing` event to detect weapon swings and apply damage to hit objects.

```holoscript
object Crate @pointable {
  geometry: 'model/crate.glb'
  state: 'closed'

  inventory: {
    slots: 6
    items: []
  }

  states: {
    closed: { lidRotation: 0 }
    open: { lidRotation: -110 }
  }

  onPoint: {
    if (this.state == 'closed') {
      this.state = 'open'
      audio.play('crate_open')
      ui.showInventory(this.inventory)
    } else {
      this.state = 'closed'
      audio.play('crate_close')
      ui.hideInventory()
    }
  }
}
```

